export interface IInvitationBase {
	_id: string;
	company_id: string;
	invited_by: string;
	email: string;
	role: 'member';
	token: string;
	expires_at: Date;
	accepted_at: Date | null;
	created_at: Date;
	updated_at: Date;
	deleted_at: Date | null;
}

import type { IInvitationBase } from '@modules/invitation/types/invitation.base.interface';

export type IInvitationCreate = Omit<
	IInvitationBase,
	'_id' | 'token' | 'expires_at' | 'accepted_at' | 'created_at' | 'updated_at' | 'deleted_at'
>;

import {
	IsDate,
	IsEmail,
	IsIn,
	IsNotEmpty,
	IsOptional,
	IsString,
	IsUUID,
} from 'class-validator';

export class InvitationBaseDto {
	@IsUUID()
	@IsNotEmpty()
	_id: string;

	@IsUUID()
	@IsNotEmpty()
	company_id: string;

	@IsUUID()
	@IsNotEmpty()
	invited_by: string;

	@IsEmail()
	@IsNotEmpty()
	email: string;

	@IsIn(['member'])
	@IsNotEmpty()
	role: 'member';

	@IsString()
	@IsNotEmpty()
	token: string;

	@IsDate()
	@IsNotEmpty()
	expires_at: Date;

	@IsOptional()
	@IsDate()
	accepted_at: Date | null;

	@IsDate()
	@IsNotEmpty()
	created_at: Date;

	@IsDate()
	@IsNotEmpty()
	updated_at: Date;

	@IsOptional()
	@IsDate()
	deleted_at: Date | null;
}

import { IsEmail, IsNotEmpty } from 'class-validator';

export class InvitationCreateDto {
	@IsEmail()
	@IsNotEmpty()
	email: string;
}

import { IsNotEmpty, IsString } from 'class-validator';

export class AcceptInvitationDto {
	@IsString()
	@IsNotEmpty()
	token: string;
}

import { randomBytes, randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { InvitationBaseDto } from '@modules/invitation/dto/invitation.base.dto';
import { IInvitationBase } from '@modules/invitation/types/invitation.base.interface';
import { IInvitationCreate } from '@modules/invitation/types/invitation.create.interface';

import { TABLE_NAME_INVITATIONS } from '@constants/db.constant';

const INVITATION_EXPIRY_MS = 72 * 60 * 60 * 1000;

@Injectable()
export class InvitationModel {
	private readonly logger = new Logger(InvitationModel.name);
	private readonly tableName = TABLE_NAME_INVITATIONS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async findByToken({
		token,
	}: {
		token: string;
	}): Promise<IInvitationBase | null> {
		try {
			const result = await this.knexRead<IInvitationBase>(this.tableName)
				.where({ token })
				.whereNull('accepted_at')
				.whereNull('deleted_at')
				.where('expires_at', '>', this.knexRead.fn.now())
				.first();

			if (!result) {
				return null;
			}

			const dto = plainToInstance(InvitationBaseDto, result);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for invitation data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			return result;
		} catch (error) {
			this.logger.error(
				`Failed to find invitation by token: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findPendingByCompanyId({
		companyId,
	}: {
		companyId: IInvitationBase['company_id'];
	}): Promise<IInvitationBase[]> {
		try {
			const results = await this.knexRead<IInvitationBase>(this.tableName)
				.where({ company_id: companyId })
				.whereNull('accepted_at')
				.whereNull('deleted_at')
				.where('expires_at', '>', this.knexRead.fn.now());

			return results;
		} catch (error) {
			this.logger.error(
				`Failed to find pending invitations for company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async create({ data }: { data: IInvitationCreate }): Promise<IInvitationBase> {
		try {
			const token = randomBytes(48).toString('base64url');
			const expiresAt = new Date(Date.now() + INVITATION_EXPIRY_MS);

			const _id = randomUUID();
			const [created] = await this.knexWrite<IInvitationBase>(this.tableName)
				.insert({
					_id,
					...data,
					token,
					expires_at: expiresAt,
					accepted_at: null,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create invitation');
			}

			this.logger.debug(`Created invitation with id ${_id}`);
			return created;
		} catch (error) {
			this.logger.error(`Failed to create invitation: ${(error as Error).message}`);
			throw error;
		}
	}

	async markAccepted({ invitationId }: { invitationId: IInvitationBase['_id'] }): Promise<void> {
		try {
			await this.knexWrite<IInvitationBase>(this.tableName)
				.where({ _id: invitationId })
				.update({
					accepted_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Marked invitation ${invitationId} as accepted`);
		} catch (error) {
			this.logger.error(
				`Failed to mark invitation ${invitationId} as accepted: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async softDelete({ invitationId }: { invitationId: IInvitationBase['_id'] }): Promise<void> {
		try {
			await this.knexWrite<IInvitationBase>(this.tableName)
				.where({ _id: invitationId })
				.whereNull('deleted_at')
				.update({
					deleted_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Soft deleted invitation ${invitationId}`);
		} catch (error) {
			this.logger.error(
				`Failed to soft delete invitation ${invitationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}
}

import { BadRequestException, Injectable, NotFoundException } from '@nestjs/common';

import { CompanyMemberService } from '@modules/company-member/company-member.service';
import { InvitationModel } from '@modules/invitation/invitation.model';
import { IInvitationBase } from '@modules/invitation/types/invitation.base.interface';

@Injectable()
export class InvitationService {
	constructor(
		private readonly invitationModel: InvitationModel,
		private readonly companyMemberService: CompanyMemberService,
	) {}

	async createInvitation({
		companyId,
		email,
		invitedBy,
	}: {
		companyId: string;
		email: string;
		invitedBy: string;
	}): Promise<IInvitationBase> {
		const pending = await this.invitationModel.findPendingByCompanyId({ companyId });
		const existing = pending.find((inv) => inv.email === email);
		if (existing) {
			throw new BadRequestException(
				`A pending invitation already exists for ${email} in this company`,
			);
		}

		return this.invitationModel.create({
			data: {
				company_id: companyId,
				email,
				invited_by: invitedBy,
				role: 'member',
			},
		});
	}

	async acceptInvitation({
		token,
		userId,
		userEmail,
	}: {
		token: string;
		userId: string;
		userEmail: string;
	}): Promise<void> {
		const invitation = await this.invitationModel.findByToken({ token });
		if (!invitation) {
			throw new NotFoundException('Invitation not found or has expired');
		}

		if (invitation.email !== userEmail) {
			throw new BadRequestException('This invitation was sent to a different email address');
		}

		await this.companyMemberService.create({
			data: {
				user_id: userId,
				company_id: invitation.company_id,
				role: invitation.role,
			},
		});

		await this.invitationModel.markAccepted({ invitationId: invitation._id });
	}

	async revokeInvitation({ invitationId }: { invitationId: string }): Promise<void> {
		return this.invitationModel.softDelete({ invitationId });
	}

	async listPendingInvitations({
		companyId,
	}: {
		companyId: string;
	}): Promise<IInvitationBase[]> {
		return this.invitationModel.findPendingByCompanyId({ companyId });
	}
}

import {
	Body,
	Controller,
	Delete,
	Get,
	HttpCode,
	HttpStatus,
	NotFoundException,
	Param,
	Post,
	Query,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import { Throttle } from '@nestjs/throttler';

import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
import { Public } from '@modules/auth/decorators/public.decorator';
